203→  <script>
204→    // Image drag & drop / paste handling
205→    (function() {
206→      const panel = document.getElementById('mcp-chat-panel');
207→      if (!panel) return;
208→
209→      let dragCounter = 0;
210→
211→      panel.addEventListener('dragenter', (e) => {
212→        e.preventDefault();
213→        dragCounter++;
214→        panel.classList.add('drag-over');
215→      });
216→
217→      panel.addEventListener('dragleave', (e) => {
218→        dragCounter--;
219→        if (dragCounter <= 0) {
220→          dragCounter = 0;
221→          panel.classList.remove('drag-over');
222→        }
223→      });
224→
225→      panel.addEventListener('dragover', (e) => {
226→        e.preventDefault();
227→      });
228→
229→      panel.addEventListener('drop', (e) => {
230→        e.preventDefault();
231→        dragCounter = 0;
232→        panel.classList.remove('drag-over');
233→        if (e.dataTransfer && e.dataTransfer.files) {
234→          handleImageFiles(e.dataTransfer.files);
235→        }
236→      });
237→
238→      // Paste handler
239→      panel.addEventListener('paste', (e) => {
240→        const items = e.clipboardData && e.clipboardData.items;
241→        if (!items) return;
242→        const files = [];
243→        for (const item of items) {
244→          if (item.type.startsWith('image/')) {
245→            const file = item.getAsFile();
246→            if (file) files.push(file);
247→          }
248→        }
249→        if (files.length > 0) handleImageFiles(files);
250→      });
251→
252→      function handleImageFiles(files) {
253→        for (const file of files) {
254→          if (!file.type.startsWith('image/')) continue;
255→          const reader = new FileReader();
256→          reader.onload = (e) => {
257→            const dataUri = e.target.result;
258→            const base64Data = dataUri.split(',')[1];
259→            generateThumbnail(dataUri, 150).then((thumbnail) => {
260→              const payload = JSON.stringify({
261→                filename: file.name || 'image.png',
262→                mime: file.type,
263→                base64: base64Data,
264→                thumbnail: thumbnail,
265→                fullUri: dataUri
266→              });
267→              const tryUpdate = () => {
268→                if (window.uiApp) {
269→                  window.uiApp.updateValue('image-bridge', payload);
270→                } else {
271→                  setTimeout(tryUpdate, 50);
272→                }
273→              };
274→              tryUpdate();
275→            });
276→          };
277→          reader.readAsDataURL(file);
278→        }
279→      }
280→
281→      function generateThumbnail(dataUri, maxDim) {
282→        return new Promise((resolve) => {
283→          const img = new Image();
284→          img.onload = () => {
285→            const canvas = document.createElement('canvas');
286→            let w = img.width, h = img.height;
287→            if (w > maxDim || h > maxDim) {
288→              if (w > h) { h = Math.round(h * maxDim / w); w = maxDim; }
289→              else { w = Math.round(w * maxDim / h); h = maxDim; }
290→            }
291→            canvas.width = w;
292→            canvas.height = h;
293→            canvas.getContext('2d').drawImage(img, 0, 0, w, h);
294→            resolve(canvas.toDataURL('image/jpeg', 0.7));
295→          };
296→          img.onerror = () => resolve('');
297→          img.src = dataUri;
298→        });
299→      }
300→    })();
301→  </script>
