303→  <script>
304→    // Chat panel resize handle (timer-loop drag)
305→    // See .ui/patterns/event-compression.md
306→    (function() {
307→      const panel = document.getElementById('mcp-chat-panel');
308→      const handle = document.getElementById('mcp-chat-resize-handle');
309→      if (!panel || !handle) return;
310→
311→      let startY, startHeight, currentY, lastY, rafId;
312→
313→      handle.addEventListener('mousedown', (e) => {
314→        startY = currentY = lastY = e.clientY;
315→        startHeight = panel.offsetHeight;
316→        panel.querySelectorAll('iframe').forEach(f => f.style.pointerEvents = 'none');
317→        document.addEventListener('mousemove', onDrag);
318→        document.addEventListener('mouseup', onRelease);
319→        rafLoop();
320→        e.preventDefault();
321→      });
322→
323→      function onDrag(e) {
324→        currentY = e.clientY;
325→      }
326→
327→      function rafLoop() {
328→        rafId = requestAnimationFrame(() => {
329→          if (currentY !== lastY) {
330→            lastY = currentY;
331→            const height = Math.max(120, Math.min(window.innerHeight * 0.6, startHeight + (startY - currentY)));
332→            panel.style.height = height + 'px';
333→          }
334→          rafLoop();
335→        });
336→      }
337→
338→      function onRelease() {
339→        cancelAnimationFrame(rafId);
340→        document.removeEventListener('mousemove', onDrag);
341→        document.removeEventListener('mouseup', onRelease);
342→        panel.querySelectorAll('iframe').forEach(f => f.style.pointerEvents = '');
343→      }
344→    })();
345→  </script>
