349→    // Find which viewdef an element belongs to by walking up and checking preceding siblings
350→    window.uiApp.findViewdef = function(elementId) {
351→      var el = document.getElementById(elementId);
352→      while (el) {
353→        if (el.getAttribute && el.getAttribute('ui-viewdef')) return el.getAttribute('ui-viewdef');
354→        var sib = el.previousElementSibling;
355→        while (sib) {
356→          if (sib.getAttribute && sib.getAttribute('ui-viewdef')) return sib.getAttribute('ui-viewdef');
357→          sib = sib.previousElementSibling;
358→        }
359→        el = el.parentElement;
360→      }
361→      return null;
362→    };
363→    // Find viewdef and send result to Lua via bridge
364→    window.uiApp.reportViewdef = function(elementId) {
365→      window.uiApp.updateValue('viewdef-bridge', window.uiApp.findViewdef(elementId) || '');
366→    };
367→  </script>
