370→    // Mouse tracker + highlight utility for agent-driven UI pointing
371→    (function() {
372→      window._mousePos = {x: 0, y: 0};
373→      document.addEventListener("mousemove", function(e) {
374→        window._mousePos.x = e.clientX;
375→        window._mousePos.y = e.clientY;
376→      });
377→
378→      window.uiApp.highlight = function(elementId) {
379→        var mp = window._mousePos;
380→        var el = document.getElementById(elementId);
381→        if (el == null) return;
382→        var r = el.getBoundingClientRect();
383→        if (r.width == 0) return;
384→        var br = getComputedStyle(el).borderRadius;
385→        // Box-shadow ring
386→        el.style.boxShadow = "0 0 0 3px #E07A47, 0 0 12px rgba(224,122,71,0.6)";
387→        el.style.transition = "box-shadow 2s ease-out";
388→        setTimeout(function() { el.style.boxShadow = "0 0 0 3px transparent"; }, 2000);
389→        setTimeout(function() { el.style.boxShadow = ""; el.style.transition = ""; }, 4000);
390→        // Translucent overlay
391→        var ov = document.createElement("div");
392→        ov.style.cssText = "position:fixed;pointer-events:none;z-index:9998;background:rgba(224,122,71,0.15);border:2px solid rgba(224,122,71,0.5);border-radius:" + br + ";transition:opacity 2s ease-out;";
393→        ov.style.left = r.left + "px"; ov.style.top = r.top + "px";
394→        ov.style.width = r.width + "px"; ov.style.height = r.height + "px";
395→        document.body.appendChild(ov);
396→        setTimeout(function() { ov.style.opacity = "0"; }, 1000);
397→        setTimeout(function() { ov.remove(); }, 3000);
398→        // SVG dashed connector from mouse to element center
399→        var cx = r.left + r.width / 2, cy = r.top + r.height / 2;
400→        var svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
401→        svg.style.cssText = "position:fixed;top:0;left:0;width:100vw;height:100vh;pointer-events:none;z-index:9999;";
402→        var line = document.createElementNS("http://www.w3.org/2000/svg", "line");
403→        line.setAttribute("x1", mp.x); line.setAttribute("y1", mp.y);
404→        line.setAttribute("x2", cx); line.setAttribute("y2", cy);
405→        line.setAttribute("stroke", "#E07A47"); line.setAttribute("stroke-width", "2");
406→        line.setAttribute("stroke-dasharray", "6 4");
407→        var dot = document.createElementNS("http://www.w3.org/2000/svg", "circle");
408→        dot.setAttribute("cx", cx); dot.setAttribute("cy", cy);
409→        dot.setAttribute("r", "4"); dot.setAttribute("fill", "#E07A47");
410→        svg.appendChild(line); svg.appendChild(dot);
411→        document.body.appendChild(svg);
412→        setTimeout(function() { svg.style.transition = "opacity 2s ease-out"; svg.style.opacity = "0"; }, 1000);
413→        setTimeout(function() { svg.remove(); }, 3000);
414→      };
415→    })();
416→  </script>
