.mcp-dialog-header {
  padding: 16px 20px;
  font-family: var(--term-sans, sans-serif);
  font-size: 1.1em;
  font-weight: 600;
  color: var(--term-text, #e0e0e8);
  border-bottom: 1px solid var(--term-border, #2a2a3a);
}

.mcp-dialog-body {
  padding: 16px 20px;
  color: var(--term-text-dim, #8888a0);
}

.mcp-dialog-body p { margin: 0 0 8px 0; }
.mcp-dialog-body p:last-child { margin-bottom: 0; }

.mcp-dialog-footer {
  padding: 12px 20px;
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  border-top: 1px solid var(--term-border, #2a2a3a);
}

