.mcp-dialog-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}
.mcp-dialog-overlay.hidden { display: none; }
.mcp-dialog-overlay.hidden.showing { display: flex; }

.mcp-dialog {
  background: var(--term-bg-elevated, #12121a);
  border: 1px solid var(--term-border, #2a2a3a);
